function hasDuplicate(values: number[]): boolean {
  for (let i = 0; i < values.length; i++) {
    for (let j = i + 1; j < values.length; j++) {
      if (values[i] === values[j]) return true;
    }
  }
  return false;
}

function reverse(values: string[]): void {
  let left = 0;
  let right = values.length - 1;
  while (left < right) {
    [values[left], values[right]] = [values[right], values[left]];
    left++;
    right--;
  }
}

function bfs(start: number, graph: number[][]): number[] {
  const queue = [start];
  const seen = new Set([start]);
  const order: number[] = [];
  while (queue.length) {
    const node = queue.shift()!;
    order.push(node);
    for (const next of graph[node]) {
      if (!seen.has(next)) {
        seen.add(next);
        queue.push(next);
      }
    }
  }
  return order;
}

function frequencies(values: string[]): Map<string, number> {
  const counts = new Map<string, number>();
  for (const value of values) {
    counts.set(value, (counts.get(value) ?? 0) + 1);
  }
  return counts;
}

function search(path: number[], choices: number[]): void {
  if (done(path)) {
    record(path);
    return;
  }
  for (const choice of choices) {
    if (!valid(path, choice)) continue;
    path.push(choice);
    search(path, nextChoices(path, choices));
    path.pop();
  }
}

function binarySearch(values: number[], target: number): number {
  let left = 0;
  let right = values.length - 1;
  while (left <= right) {
    const mid = left + Math.floor((right - left) / 2);
    if (values[mid] === target) return mid;
    if (values[mid] < target) left = mid + 1;
    else right = mid - 1;
  }
  return -1;
}

function inorder(node: TreeNode | null, out: number[]): void {
  if (!node) return;
  inorder(node.left, out);
  out.push(node.value);
  inorder(node.right, out);
}

function topK(values: number[], k: number): number[] {
  const heap: number[] = [];
  for (const value of values) {
    pushMinHeap(heap, value);
    if (heap.length > k) popMinHeap(heap);
  }
  return heap;
}

function dfs(node: number, graph: number[][], seen: Set<number>): void {
  if (seen.has(node)) return;
  seen.add(node);
  for (const next of graph[node]) {
    dfs(next, graph, seen);
  }
}

function maxNonOverlapping(intervals: Array<[number, number]>): number {
  intervals.sort((a, b) => a[1] - b[1]);
  let count = 0;
  let end = -Infinity;
  for (const [start, finish] of intervals) {
    if (start >= end) {
      count++;
      end = finish;
    }
  }
  return count;
}

function climbStairs(n: number): number {
  if (n <= 2) return n;
  const dp = new Array(n + 1).fill(0);
  dp[1] = 1;
  dp[2] = 2;
  for (let i = 3; i <= n; i++) {
    dp[i] = dp[i - 1] + dp[i - 2];
  }
  return dp[n];
}

class UnionFind {
  parent: number[];
  rank: number[];
  constructor(n: number) {
    this.parent = Array.from({ length: n }, (_, i) => i);
    this.rank = new Array(n).fill(0);
  }
  find(x: number): number {
    if (this.parent[x] !== x) this.parent[x] = this.find(this.parent[x]);
    return this.parent[x];
  }
}

